import{_ as t,o as r,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"32. Transition To Retirement","description":"","frontmatter":{"title":"32. Transition To Retirement","eba":"Doctors in Training 2022-2026","topics":["employment","flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/32-transition-to-retirement.md","filePath":"ebas/doctors-in-training/doctor-employment/32-transition-to-retirement.md"}'),i={name:"ebas/doctors-in-training/doctor-employment/32-transition-to-retirement.md"};function a(s,e,p,l,m,g){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_32-transition-to-retirement" tabindex="-1">32. Transition To Retirement <a class="header-anchor" href="#_32-transition-to-retirement" aria-label="Permalink to &quot;32. Transition To Retirement&quot;">​</a></h1><p><strong>32.1</strong> A Doctor may advise their Health Service in writing of their intention to retire within the next five years and participate in a retirement transition arrangement.</p><p><strong>32.2</strong> Transition to retirement arrangements may be proposed and, where agreed, implemented as:</p><p><strong>(a)</strong> a flexible working arrangement (see <a href="/eba/ebas/doctors-in-training/consultation-disputes/15-flexible-working-arrangements.html">clause 15</a> (Flexible Working Arrangements)),</p><p><strong>(b)</strong> in writing between the parties, or</p><p><strong>(c)</strong> any combination of the above.</p><p><strong>32.3</strong> A transition to retirement arrangement may include but is not limited to:</p><p><strong>(a)</strong> a reduction in their EFT;</p><p><strong>(b)</strong> a job share arrangement;</p><p><strong>(c)</strong> working in a position at a lower classification or rate of pay.</p><p><strong>32.4</strong> The Health Service will consider, and not unreasonably refuse, a request by a Doctor who wishes to transition to retirement:</p><p><strong>(a)</strong> to use accrued Long Service Leave (LSL) or Annual Leave for the purpose of reducing the number of days worked per week while retaining their previous employment status; or</p><p><strong>(b)</strong> to be appointed to a role that has a lower hourly rate of pay or hours (post transition role), in which case:</p><p><strong>(i)</strong> the Health Service will preserve the accrual of LSL at the time of reduction in salary or hours; and</p><p><strong>(ii)</strong> where LSL is taken or paid out in lieu on termination, the Doctor will be paid LSL hours at the applicable classification and grade, and at the preserved hours, prior to the post transition role until the preserved LSL hours are exhausted.</p><p>Plain language terms: phased retirement, TTR.</p>',16)])])}const h=t(i,[["render",a]]);export{d as __pageData,h as default};
